import re
from flask import Flask, request, jsonify
from functools import wraps
import redis
import os

app = Flask(__name__)

redis_client = redis.Redis(
    host=os.environ.get('REDIS_HOST', 'localhost'),
    port=int(os.environ.get('REDIS_PORT', 6379)),
    db=int(os.environ.get('REDIS_DB', 0)),
    password=os.environ.get('REDIS_PASSWORD', None),
    decode_responses=True
)

API_KEY = os.environ.get('ADMIN_API_KEY', 'change-me-in-production')

ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'EXPIRE', 'TTL', 'PTTL',
    'KEYS', 'SCAN', 'TYPE', 'MGET', 'MSET',
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS', 'HEXISTS',
    'LRANGE', 'LLEN', 'LPUSH', 'RPUSH', 'LPOP', 'RPOP',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER', 'SCARD',
    'ZADD', 'ZREM', 'ZRANGE', 'ZRANGEBYSCORE', 'ZCARD', 'ZSCORE',
    'DBSIZE', 'INFO', 'PING',
    'SETEX', 'PSETEX', 'SETNX',
    'INCR', 'DECR', 'INCRBY', 'DECRBY',
    'APPEND', 'STRLEN',
}

DENIED_COMMANDS = {
    'FLUSHALL', 'FLUSHDB', 'CONFIG', 'SHUTDOWN', 'SLAVEOF', 'REPLICAOF',
    'DEBUG', 'EVAL', 'EVALSHA', 'SCRIPT', 'MODULE', 'ACL',
    'BGSAVE', 'BGREWRITEAOF', 'SAVE', 'MIGRATE', 'CLUSTER',
    'CLIENT', 'COMMAND', 'LATENCY', 'MEMORY', 'OBJECT',
    'PFSELFTEST', 'PSYNC', 'REPLCONF', 'RESTORE', 'SORT',
    'SWAPDB', 'WAIT', 'XGROUP', 'XINFO',
}

MAX_KEY_LENGTH = 256
MAX_VALUE_LENGTH = 10240
MAX_ARGS = 20
KEY_PATTERN = re.compile(r'^[a-zA-Z0-9_\-:.\/\*\[\]{}]+$')


def require_api_key(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key != API_KEY:
            return jsonify({'error': 'Unauthorized. Valid API key required.'}), 401
        return f(*args, **kwargs)
    return decorated


def validate_command(command_str):
    if not command_str or not command_str.strip():
        return None, "Empty command"

    parts = command_str.strip().split()
    if not parts:
        return None, "Empty command"

    cmd_name = parts[0].upper()

    if cmd_name in DENIED_COMMANDS:
        return None, f"Command '{cmd_name}' is explicitly denied for security reasons"

    if cmd_name not in ALLOWED_COMMANDS:
        return None, f"Command '{cmd_name}' is not in the allowed commands list"

    if len(parts) > MAX_ARGS + 1:
        return None, f"Too many arguments. Maximum is {MAX_ARGS}"

    args = parts[1:]
    for i, arg in enumerate(args):
        if len(arg) > MAX_VALUE_LENGTH:
            return None, f"Argument {i+1} exceeds maximum length of {MAX_VALUE_LENGTH}"

    if args and cmd_name not in ('INFO', 'PING', 'DBSIZE'):
        key = args[0]
        if len(key) > MAX_KEY_LENGTH:
            return None, f"Key length exceeds maximum of {MAX_KEY_LENGTH}"
        if not KEY_PATTERN.match(key):
            return None, f"Key contains invalid characters. Allowed: alphanumeric, _, -, :, ., /, *, [], {{}}"

    if cmd_name == 'KEYS' and args:
        pattern = args[0]
        if pattern == '*':
            return None, "Wildcard-only KEYS pattern is not allowed. Use SCAN instead."

    return (cmd_name, args), None


@app.route('/api/redis/execute', methods=['GET', 'POST'])
@require_api_key
def execute_redis_command():
    if request.method == 'POST':
        data = request.get_json(silent=True) or {}
        command_str = data.get('command', '')
    else:
        command_str = request.args.get('command', '')

    parsed, error = validate_command(command_str)
    if error:
        return jsonify({
            'success': False,
            'error': error,
            'allowed_commands': sorted(ALLOWED_COMMANDS)
        }), 400

    cmd_name, args = parsed

    try:
        result = redis_client.execute_command(cmd_name, *args)

        if isinstance(result, bytes):
            result = result.decode('utf-8', errors='replace')
        elif isinstance(result, list):
            result = [
                item.decode('utf-8', errors='replace') if isinstance(item, bytes) else item
                for item in result
            ]
        elif isinstance(result, dict):
            result = {
                (k.decode('utf-8', errors='replace') if isinstance(k, bytes) else k):
                (v.decode('utf-8', errors='replace') if isinstance(v, bytes) else v)
                for k, v in result.items()
            }

        return jsonify({
            'success': True,
            'command': cmd_name,
            'args': args,
            'result': result
        }), 200

    except redis.RedisError as e:
        return jsonify({
            'success': False,
            'error': f"Redis error: {str(e)}",
            'command': cmd_name,
            'args': args
        }), 500
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f"Unexpected error: {str(e)}"
        }), 500


@app.route('/api/redis/allowed-commands', methods=['GET'])
@require_api_key
def list_allowed_commands():
    return jsonify({
        'allowed_commands': sorted(ALLOWED_COMMANDS),
        'denied_commands': sorted(DENIED_COMMANDS)
    }), 200


@app.route('/api/redis/health', methods=['GET'])
def health_check():
    try:
        redis_client.ping()
        return jsonify({'status': 'healthy', 'redis': 'connected'}), 200
    except redis.RedisError:
        return jsonify({'status': 'unhealthy', 'redis': 'disconnected'}), 503


